import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"老舍故居","description":"","frontmatter":{},"headers":[],"relativePath":"history/lao-she-residence.md","filePath":"history/lao-she-residence.md","lastUpdated":1784773307000}'),n={name:"history/lao-she-residence.md"};function o(i,t,d,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="老舍故居" tabindex="-1">老舍故居 <a class="header-anchor" href="#老舍故居" aria-label="Permalink to &quot;老舍故居&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1662792193082-9f02de0c12f0?w=1200" alt="老舍故居"></p><blockquote><p>&quot;人民艺术家，京味文学的代言人。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>老舍故居位于北京市东城区灯市口西街丰富胡同19号，是一座典型的北京四合院。老舍先生从1950年至1966年在此居住，在这里度过了人生的最后16年，也是他创作生涯最辉煌的时期。《龙须沟》《茶馆》等不朽名作均诞生于此。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-16:30（周二至周日），周一闭馆</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费（需预约）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1小时</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁5号线灯市口站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区灯市口西街丰富胡同19号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="故居由来" tabindex="-1">故居由来 <a class="header-anchor" href="#故居由来" aria-label="Permalink to &quot;故居由来&quot;">​</a></h3><p>1950年，老舍从美国讲学归来，购置了这座四合院。这座宅院成为他后半生的居所，也是他创作《龙须沟》《茶馆》等名作的地方。</p><h3 id="晚年岁月" tabindex="-1">晚年岁月 <a class="header-anchor" href="#晚年岁月" aria-label="Permalink to &quot;晚年岁月&quot;">​</a></h3><p>在这16年间，老舍先生创作了《龙须沟》《茶馆》《正红旗下》等重要作品，并荣获&quot;人民艺术家&quot;称号。</p><h4 id="创作年表" tabindex="-1">创作年表 <a class="header-anchor" href="#创作年表" aria-label="Permalink to &quot;创作年表&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">作品</th></tr></thead><tbody><tr><td style="text-align:left;">1950年</td><td style="text-align:left;">从美国归来，入住丰富胡同</td></tr><tr><td style="text-align:left;">1951年</td><td style="text-align:left;">创作《龙须沟》，获&quot;人民艺术家&quot;称号</td></tr><tr><td style="text-align:left;">1956年</td><td style="text-align:left;">创作《茶馆》</td></tr><tr><td style="text-align:left;">1966年</td><td style="text-align:left;">文革开始，8月24日逝世</td></tr></tbody></table><h2 id="故居布局" tabindex="-1">故居布局 <a class="header-anchor" href="#故居布局" aria-label="Permalink to &quot;故居布局&quot;">​</a></h2><h3 id="四合院结构" tabindex="-1">四合院结构 <a class="header-anchor" href="#四合院结构" aria-label="Permalink to &quot;四合院结构&quot;">​</a></h3><p>老舍故居是一座典型的老北京四合院，占地约500平方米。</p><h4 id="建筑布局" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">建筑</th><th style="text-align:left;">功能</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>大门</strong></td><td style="text-align:left;">入口</td><td style="text-align:left;">传统朱漆大门</td></tr><tr><td style="text-align:left;"><strong>影壁</strong></td><td style="text-align:left;">照壁</td><td style="text-align:left;">砖雕影壁</td></tr><tr><td style="text-align:left;"><strong>正房</strong></td><td style="text-align:left;">第一展室</td><td style="text-align:left;">生平与创作历程展</td></tr><tr><td style="text-align:left;"><strong>东厢房</strong></td><td style="text-align:left;">第二展室</td><td style="text-align:left;">生活用品、家庭照片</td></tr><tr><td style="text-align:left;"><strong>西厢房</strong></td><td style="text-align:left;">第三展室</td><td style="text-align:left;">代表作品、手稿</td></tr><tr><td style="text-align:left;"><strong>后院</strong></td><td style="text-align:left;">花园</td><td style="text-align:left;">太平花、丁香</td></tr></tbody></table><h3 id="主要展室" tabindex="-1">主要展室 <a class="header-anchor" href="#主要展室" aria-label="Permalink to &quot;主要展室&quot;">​</a></h3><h4 id="第一展室-正房" tabindex="-1">第一展室（正房） <a class="header-anchor" href="#第一展室-正房" aria-label="Permalink to &quot;第一展室（正房）&quot;">​</a></h4><p>展示老舍先生的生平与创作历程。</p><ul><li><strong>生平介绍</strong>：从出生到逝世的生平事迹</li><li><strong>创作历程</strong>：各时期的代表作品</li><li><strong>荣誉展示</strong>：获得的荣誉和称号</li></ul><h4 id="第二展室-东厢房" tabindex="-1">第二展室（东厢房） <a class="header-anchor" href="#第二展室-东厢房" aria-label="Permalink to &quot;第二展室（东厢房）&quot;">​</a></h4><p>展示老舍先生的生活用品和家庭照片。</p><ul><li><strong>生活用品</strong>：眼镜、毛笔、茶具等</li><li><strong>家庭照片</strong>：与家人、友人的合影</li><li><strong>剧照</strong>：《茶馆》《龙须沟》首演照片</li></ul><h4 id="第三展室-西厢房" tabindex="-1">第三展室（西厢房） <a class="header-anchor" href="#第三展室-西厢房" aria-label="Permalink to &quot;第三展室（西厢房）&quot;">​</a></h4><p>展示老舍先生的代表作品和手稿。</p><ul><li><strong>手稿</strong>：《正红旗下》等作品原稿</li><li><strong>著作</strong>：各种版本的著作</li><li><strong>藏书</strong>：约2500册藏书</li></ul><h2 id="珍贵藏品" tabindex="-1">珍贵藏品 <a class="header-anchor" href="#珍贵藏品" aria-label="Permalink to &quot;珍贵藏品&quot;">​</a></h2><h3 id="手稿和著作" tabindex="-1">手稿和著作 <a class="header-anchor" href="#手稿和著作" aria-label="Permalink to &quot;手稿和著作&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">文物</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>《正红旗下》手稿</strong></td><td style="text-align:left;">未完成的遗作</td></tr><tr><td style="text-align:left;"><strong>《茶馆》剧本</strong></td><td style="text-align:left;">首演版本</td></tr><tr><td style="text-align:left;"><strong>《龙须沟》手稿</strong></td><td style="text-align:left;">创作手稿</td></tr><tr><td style="text-align:left;"><strong>著作版本</strong></td><td style="text-align:left;">各种语言的译本</td></tr></tbody></table><h3 id="生活用品" tabindex="-1">生活用品 <a class="header-anchor" href="#生活用品" aria-label="Permalink to &quot;生活用品&quot;">​</a></h3><ul><li><strong>眼镜</strong>：老舍生前戴的眼镜</li><li><strong>毛笔</strong>：创作时使用的毛笔</li><li><strong>茶具</strong>：喝茶用的茶具</li><li><strong>印章</strong>：个人印章</li></ul><h3 id="艺术藏品" tabindex="-1">艺术藏品 <a class="header-anchor" href="#艺术藏品" aria-label="Permalink to &quot;艺术藏品&quot;">​</a></h3><ul><li><strong>齐白石画</strong>：《蛙声十里出山泉》等</li><li><strong>剧照</strong>：《茶馆》《龙须沟》首演照片</li><li><strong>藏书</strong>：约2500册中外书籍</li></ul><h2 id="后院花园" tabindex="-1">后院花园 <a class="header-anchor" href="#后院花园" aria-label="Permalink to &quot;后院花园&quot;">​</a></h2><h3 id="太平花" tabindex="-1">太平花 <a class="header-anchor" href="#太平花" aria-label="Permalink to &quot;太平花&quot;">​</a></h3><p>后院种植着两棵太平花，是老舍先生亲手栽种的。每年春夏之交，太平花盛开，香气袭人。</p><h3 id="其他花木" tabindex="-1">其他花木 <a class="header-anchor" href="#其他花木" aria-label="Permalink to &quot;其他花木&quot;">​</a></h3><p>院内还种植着丁香、黄刺玫、榆叶梅等花木，都是老舍先生生前喜爱的植物。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>精华路线（约1小时）</strong>：</p><p>入口 → 影壁 → 第一展室（生平） → 第二展室（生活用品） → 第三展室（作品手稿） → 后院（太平花） → 出口</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>提前预约</strong>：建议提前在微信公众号&quot;老舍纪念馆&quot;预约</li><li><strong>最佳时间</strong>：春夏时节，太平花开时最美</li><li><strong>拍照位置</strong>：影壁、正房前、后院太平花下都是绝佳拍照点</li><li><strong>讲解服务</strong>：可以请导游讲解，了解更多故事</li><li><strong>周边游览</strong>：参观完后可以到王府井、中国美术馆游览</li></ol><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地铁</strong></td><td style="text-align:left;">5号线灯市口站A口，步行约5分钟</td></tr><tr><td style="text-align:left;"><strong>公交</strong></td><td style="text-align:left;">103、104、108、111路灯市口站</td></tr><tr><td style="text-align:left;"><strong>打车</strong></td><td style="text-align:left;">定位&quot;老舍故居&quot;即可</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">王府井大街</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">商业步行街</td></tr><tr><td style="text-align:left;">中国美术馆</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">美术展览</td></tr><tr><td style="text-align:left;">故宫</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">明清皇宫</td></tr><tr><td style="text-align:left;">北大红楼</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">新文化运动遗址</td></tr></tbody></table><h2 id="文化故事" tabindex="-1">文化故事 <a class="header-anchor" href="#文化故事" aria-label="Permalink to &quot;文化故事&quot;">​</a></h2><h3 id="老舍-笔名的由来" tabindex="-1">&quot;老舍&quot;笔名的由来 <a class="header-anchor" href="#老舍-笔名的由来" aria-label="Permalink to &quot;&quot;老舍&quot;笔名的由来&quot;">​</a></h3><p>老舍原名舒庆春，他把&quot;舒&quot;字拆开，取&quot;舍&quot;和&quot;予&quot;，寓意&quot;舍弃自我&quot;。这个笔名伴随他一生，成为京味文学的标志。</p><h3 id="《茶馆》的诞生" tabindex="-1">《茶馆》的诞生 <a class="header-anchor" href="#《茶馆》的诞生" aria-label="Permalink to &quot;《茶馆》的诞生&quot;">​</a></h3><p>1956年，老舍在故居完成了话剧《茶馆》的创作。这部剧被誉为&quot;东方舞台上的奇迹&quot;，至今仍是北京人艺的保留剧目。</p><h3 id="人民艺术家" tabindex="-1">人民艺术家 <a class="header-anchor" href="#人民艺术家" aria-label="Permalink to &quot;人民艺术家&quot;">​</a></h3><p>1951年，北京市人民政府授予老舍&quot;人民艺术家&quot;的荣誉称号，老舍成为新中国第一位获得这一称号的作家。</p><hr><p><strong>📍 地址</strong>：北京市东城区灯市口西街丰富胡同19号 <strong>🚇 地铁</strong>：5号线灯市口站A口 <strong>📞 电话</strong>：010-65142655 <strong>🌐 预约</strong>：微信公众号&quot;老舍纪念馆&quot;</p><p><strong>💡 Tips</strong>：老舍故居虽小，但处处透着书香气息。建议在太平花下多停留片刻，感受老舍先生当年创作的场景。</p>',61)])])}const u=e(n,[["render",o]]);export{f as __pageData,u as default};
